"use strict";(self.webpackChunkplvacc_wiki=self.webpackChunkplvacc_wiki||[]).push([["3140"],{6181(o,a,e){e.r(a),e.d(a,{metadata:()=>i,default:()=>p,frontMatter:()=>r,contentTitle:()=>s,toc:()=>w,assets:()=>z});var i=JSON.parse('{"id":"test/gnd-ground/parking-stand-allocation","title":"Przydzielanie stanowisk","description":"Odlatuj\u0105ce statki powietrzne","source":"@site/docs/test/gnd-ground/03-parking-stand-allocation.md","sourceDirName":"test/gnd-ground","slug":"/test/gnd-ground/parking-stand-allocation","permalink":"/test/gnd-ground/parking-stand-allocation","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{},"sidebar":"defaultSidebar","previous":{"title":"Ruch na p\u0142ycie","permalink":"/test/gnd-ground/GND-movement"},"next":{"title":"Instrukcje warunkowe","permalink":"/test/gnd-ground/conditional-instructions"}}'),n=e(4848),t=e(8453);let r={},s="Przydzielanie stanowisk",z={},w=[{value:"Odlatuj\u0105ce statki powietrzne",id:"odlatuj\u0105ce-statki-powietrzne",level:2},{value:"Przylatuj\u0105ce statki powietrzne",id:"przylatuj\u0105ce-statki-powietrzne",level:2},{value:"Stanowisko a rozmiar statku powietrznego",id:"stanowisko-a-rozmiar-statku-powietrznego",level:2},{value:"Preferencyjny system przydzielania stanowisk",id:"preferencyjny-system-przydzielania-stanowisk",level:2}];function c(o){let a={a:"a",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,t.R)(),...o.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(a.header,{children:(0,n.jsx)(a.h1,{id:"przydzielanie-stanowisk",children:"Przydzielanie stanowisk"})}),"\n",(0,n.jsx)(a.h2,{id:"odlatuj\u0105ce-statki-powietrzne",children:"Odlatuj\u0105ce statki powietrzne"}),"\n",(0,n.jsx)(a.p,{children:"W realnym \u015Bwiecie stanowiska postojowe przydzielane s\u0105 liniom lotniczym oraz obs\u0142ugiwanym przez nie statkom powietrznym z uwzgl\u0119dnieniem wielu czynnik\xf3w, takich jak typ samolotu, przewidywany czas postoju, obs\u0142ugiwane kierunki lot\xf3w (np. Schengen / Non-Schengen) czy chocia\u017Cby koszty, jakie linia musi ponie\u015B\u0107 w zwi\u0105zku z korzystaniem z konkretnych udogodnie\u0144 technicznych (np. r\u0119kaw). Sie\u0107 VATSIM rz\u0105dzi si\u0119 swoimi prawami i jako kontroler cz\u0119sto nie mamy wp\u0142ywu na to, na jakim stanowisku postanowi zalogowa\u0107 si\u0119 dany pilot przed rozpocz\u0119ciem swojego lotu. Mo\u017Cemy podj\u0105\u0107 interwencj\u0119 (zwracaj\u0105c si\u0119 do pilota z pro\u015Bb\u0105 o ponowne zalogowanie si\u0119 do sieci na prawid\u0142owym stanowisku), je\u015Bli kto\u015B pojawi si\u0119 na stanowisku wyra\u017Anie niedopasowanym do typu samolotu wykorzystywanego do danego lotu lub na stanowisku, z kt\xf3rego nie jest mo\u017Cliwe doko\u0142owanie do pasa w u\u017Cyciu ze wzgl\u0119du na ograniczenia dotycz\u0105ce np. dr\xf3g ko\u0142owania."}),"\n",(0,n.jsx)(a.h2,{id:"przylatuj\u0105ce-statki-powietrzne",children:"Przylatuj\u0105ce statki powietrzne"}),"\n",(0,n.jsxs)(a.p,{children:["Nieco \u0142atwiej sytuacja wygl\u0105da w przypadku przylot\xf3w, gdy\u017C w\xf3wczas oprogramowanie EuroScope na podstawie umieszczonych w pliku sektora algorytm\xf3w automatycznie proponuje stanowisko postojowe, uwzgl\u0119dniaj\u0105c co najmniej kategori\u0119 statku powietrznego i ograniczenia zapisane w konfiguracji lotniska, a na lotniskach z wydzielonymi strefami Schengen / Non-Schengen (np. EPWA), bierze pod uwag\u0119 r\xf3wnie\u017C ten czynnik. Numer proponowanego stanowiska pojawia si\u0119 w kolumnie ",(0,n.jsx)(a.strong,{children:"Stand"})," listy ",(0,n.jsx)(a.strong,{children:"Arrival List"}),"."]}),"\n",(0,n.jsx)(a.p,{children:"Oczywi\u015Bcie ostatecznie to kontroler decyduje o przydziale stanowiska - za\u0142oga mo\u017Ce poprosi\u0107 o konkretne stanowisko, inne ni\u017C to przydzielone przez oprogramowanie, albo mo\u017Ce okaza\u0107 si\u0119, \u017Ce w trakcie ko\u0142owania na stanowisku wskazanym przez EuroScope kto\u015B si\u0119 zalogowa\u0142 i konieczne b\u0119dzie sprawne podj\u0119cie samodzielnej decyzji o przydzieleniu nowego miejsca postojowego. Trzeba zatem wiedzie\u0107, jak r\u0119cznie prawid\u0142owo przydzieli\u0107 stanowisko postojowe."}),"\n",(0,n.jsx)(a.h2,{id:"stanowisko-a-rozmiar-statku-powietrznego",children:"Stanowisko a rozmiar statku powietrznego"}),"\n",(0,n.jsxs)(a.p,{children:["W jaki spos\xf3b mo\u017Cemy sprawdzi\u0107, czy konkretne stanowisko jest odpowiednie dla danego samolotu? Z pomoc\u0105 przyjd\u0105 nam dokumenty przywo\u0142ane w cz\u0119\u015Bci ",(0,n.jsx)(a.a,{href:"/test/aerodrome#gdzie-szuka%C4%87-informacji",children:"Lotniska - Gdzie szuka\u0107 informacji?"})," oraz ",(0,n.jsx)(a.a,{href:"/test/gnd-ground/GND-movement#ograniczenia-w-ko%C5%82owaniu",children:"Ruch na p\u0142ycie"}),". Dla przypomnienia, karty zwi\u0105zane z operacjami naziemnymi na lotnisku (karta lotniska, stanowiska, karty ukazuj\u0105ce uk\u0142ad poszczeg\xf3lnych p\u0142yt postojowych) zazwyczaj znale\u017A\u0107 mo\u017Cna pod\u0105\u017Caj\u0105c \u015Bcie\u017Ck\u0105 ",(0,n.jsx)(a.a,{href:"https://www.ais.pansa.pl/publikacje/aip-polska/",children:"AIP Polska"})," IFR -> CZ\u0118\u015A\u0106 3 - LOTNISKA (AD) -> EPKK -> EPKK 2 oraz EPKK 4. Zawsze warto r\xf3wnie\u017C zaznajomi\u0107 si\u0119 z sekcj\u0105 opisow\u0105 EPKK 1, zw\u0142aszcza cz\u0119\u015Bciami od 2.20 do 2.23."]}),"\n",(0,n.jsx)(a.p,{children:"Czego mo\u017Cemy dowiedzie\u0107 si\u0119 o lotnisku Krak\xf3w-Balice, analizuj\u0105c wspomniane wy\u017Cej karty oraz zapisy AIP?"}),"\n",(0,n.jsxs)(a.ul,{children:["\n",(0,n.jsx)(a.li,{children:"karta EPKK AD 2 to AERODROME CHART, czyli karta przedstawiaj\u0105ca og\xf3lny uk\u0142ad lotniska; zawiera r\xf3wnie\u017C zapisy o szeroko\u015Bci poszczeg\xf3lnych dr\xf3g ko\u0142owania;"}),"\n",(0,n.jsx)(a.li,{children:"karta EPKK AD 4 to AIRCRAFT PARKING CHART, czyli karta dok\u0142adniej ukazuj\u0105ca poszczeg\xf3lne stanowiska, wraz z tabel\u0105 zawieraj\u0105c\u0105 w kolumnie ACFT REF. CODE liter\u0119 od A do F - jest to litera kodu referencyjnego ICAO (Aircraft Reference Code), okre\u015Blaj\u0105ca maksymaln\u0105 rozpi\u0119to\u015B\u0107 skrzyde\u0142 oraz rozstaw k\xf3\u0142 podwozia g\u0142\xf3wnego statku powietrznego, dla kt\xf3rego przeznaczone jest dane stanowisko (np. litera C oznacza rozpi\u0119to\u015B\u0107 skrzyde\u0142 od 24 do 36 metr\xf3w, a rozstaw k\xf3\u0142 podwozia g\u0142\xf3wnego od 6 do 9 m - to najpopularniejsze na Balicach samoloty, np. Airbus A320 czy Boeing 737)"}),"\n"]}),"\n",(0,n.jsx)(a.p,{children:"Zgodnie z zasad\u0105 \u201Eas real as it gets\u201D na VATSIM staramy si\u0119 przestrzega\u0107 procedur obowi\u0105zuj\u0105cych w rzeczywisto\u015Bci. W zwi\u0105zku z tym B789 (Dreamliner o rozpi\u0119to\u015Bci skrzyde\u0142 przekraczaj\u0105cej 60 m), kt\xf3ry po l\u0105dowaniu na pasie 07 zwolni\u0142 pas drog\u0105 ko\u0142owania A, powinien spodziewa\u0107 si\u0119 ko\u0142owania do jednego z odpowiednich stanowisk drogami B, W oraz Z, poniewa\u017C drogi Z4, Z5 i Z6 s\u0105 niedost\u0119pne dla samolot\xf3w o rozpi\u0119to\u015Bci skrzyde\u0142 powy\u017Cej 52 m. Z kolei l\u0105duj\u0105cy po nim B738, kt\xf3rego rozpi\u0119to\u015B\u0107 skrzyde\u0142 nie przekracza 36 m, mo\u017Ce ko\u0142owa\u0107 np. do stanowiska nr 5 bezpo\u015Brednio drog\u0105 Z."}),"\n",(0,n.jsx)(a.h2,{id:"preferencyjny-system-przydzielania-stanowisk",children:"Preferencyjny system przydzielania stanowisk"}),"\n",(0,n.jsx)(a.p,{children:"Samo dopasowanie stanowiska do rozmiar\xf3w samolotu nie zawsze oznacza, \u017Ce jest ono optymalnym wyborem. Na wielu lotniskach obowi\u0105zuje tzw. system preferencyjny, w ramach kt\xf3rego okre\u015Blonym przewo\u017Anikom przypisane s\u0105 preferowane stanowiska postojowe. Wynika to m.in. z lokalizacji zaplecza technicznego, organizacji obs\u0142ugi naziemnej czy zawartych um\xf3w handlowych. Przyk\u0142adowo samoloty bazowego przewo\u017Anika mog\u0105 by\u0107 kierowane przede wszystkim na stanowiska znajduj\u0105ce si\u0119 najbli\u017Cej terminala lub wykorzystywanej przez niego cz\u0119\u015Bci lotniska (np. w pobli\u017Cu hangar\xf3w, je\u015Bli dany przewo\u017Anik ma takowe na lotnisku), podczas gdy przewo\u017Anicy okazjonalni kierowani s\u0105 na pozosta\u0142e dost\u0119pne stanowiska spe\u0142niaj\u0105ce wymagania techniczne. W sieci VATSIM nie ma obowi\u0105zku odwzorowywania takich przydzia\u0142\xf3w z pe\u0142n\u0105 dok\u0142adno\u015Bci\u0105, jednak warto je uwzgl\u0119dnia\u0107, je\u017Celi s\u0105 opisane w lokalnych materia\u0142ach operacyjnych lub powszechnie stosowane na danym lotnisku. W przypadku kilku dost\u0119pnych stanowisk odpowiednich pod wzgl\u0119dem rozmiaru samolotu nale\u017Cy w pierwszej kolejno\u015Bci rozwa\u017Cy\u0107 stanowisko preferowane dla danego przewo\u017Anika, a dopiero w dalszej kolejno\u015Bci korzysta\u0107 z pozosta\u0142ych opcji."}),"\n",(0,n.jsx)(a.p,{children:"Je\u017Celi naprawd\u0119 chcemy zwi\u0119kszy\u0107 realizm operacji, warto w miar\u0119 mo\u017Cliwo\u015Bci obserwowa\u0107 rzeczywisty ruch na lotnisku \u2014 zar\xf3wno na \u017Cywo, jak i za pomoc\u0105 serwis\xf3w takich jak Flightradar24 \u2014 i przydziela\u0107 stanowiska w spos\xf3b mo\u017Cliwie najbardziej zbli\u017Cony do praktyki obowi\u0105zuj\u0105cej na danym lotnisku. Jako przyk\u0142ad mo\u017Ce pos\u0142u\u017Cy\u0107 Wizz Air na lotnisku Krak\xf3w-Balice. Je\u017Celi tylko pozwala na to sytuacja operacyjna, preferowanymi stanowiskami dla tego przewo\u017Anika s\u0105 te o numerach 9\u201312. Nale\u017Cy pami\u0119ta\u0107, \u017Ce system preferencyjny ma charakter pomocniczy. W pierwszej kolejno\u015Bci stanowisko musi spe\u0142nia\u0107 wszystkie ograniczenia techniczne i operacyjne (rozmiar samolotu, dost\u0119pno\u015B\u0107 dr\xf3g ko\u0142owania, podzia\u0142 Schengen / Non-Schengen itp.), a dopiero spo\u015Br\xf3d stanowisk spe\u0142niaj\u0105cych te wymagania nale\u017Cy wybiera\u0107 te preferowane dla danego przewo\u017Anika."})]})}function p(o={}){let{wrapper:a}={...(0,t.R)(),...o.components};return a?(0,n.jsx)(a,{...o,children:(0,n.jsx)(c,{...o})}):c(o)}},8453(o,a,e){e.d(a,{R:()=>r,x:()=>s});var i=e(6540);let n={},t=i.createContext(n);function r(o){let a=i.useContext(t);return i.useMemo(function(){return"function"==typeof o?o(a):{...a,...o}},[a,o])}function s(o){let a;return a=o.disableParentContext?"function"==typeof o.components?o.components(n):o.components||n:r(o.components),i.createElement(t.Provider,{value:a},o.children)}}}]);